# Feature: Real-Time Pitch Tracking Engine (DSP + ML)

## Objective
Implement a robust, real-time pitch detection module for our web application. The system must support two tiers of tracking:
1. **Low-Latency DSP:** YIN / Autocorrelation for instant, zero-dependency tracking.
2. **High-Accuracy ML:** SwiftF0 (via `onnxruntime-web`) for resilient tracking in noisy environments.

## Implementation Steps

### 1. Dependency & Asset Setup
*   Install ONNX Runtime Web: `npm install onnxruntime-web`.
*   Obtain the pre-trained `swiftf0.onnx` model and place it in the public assets directory (e.g., `/public/models/swiftf0.onnx`).

### 2. Core Audio Pipeline (Web Audio API)
*   Initialize an `AudioContext` forced to a `16000` sample rate (required by SwiftF0).
*   Request microphone permissions via `navigator.mediaDevices.getUserMedia`.
*   Route the stream into an `AnalyserNode` with an `fftSize` of 1024.

### 3. Implement the Pitch Detection Algorithms
*   Create a unified interface or manager that allows switching between DSP and ML modes on the fly.
*   Implement the DSP mathematical algorithms on standard `Float32Array` buffers.
*   Implement the WASM ONNX session handler, ensuring we slice only bins 3 through 134 from the frequency data before feeding the tensor.

## Code Reference: Unified Architecture

Please use the following TypeScript structure as the foundation for the implementation.
```typescript
import * as ort from 'onnxruntime-web';

export interface PitchResult {
  pitch: number;
  probability: number;
}

export type TrackingMode = 'dsp-yin' | 'dsp-auto' | 'ml-swift';

export class PitchTracker {
  private audioCtx: AudioContext | null = null;
  private analyser: AnalyserNode | null = null;
  private onnxSession: ort.InferenceSession | null = null;
  private mode: TrackingMode = 'dsp-yin';
  private trackingInterval: number | null = null;

  // --- 1. INITIALIZATION ---

  async init(mode: TrackingMode = 'dsp-yin', modelPath = '/models/swiftf0.onnx') {
    this.mode = mode;

    // Init Audio Pipeline
    this.audioCtx = new AudioContext({ sampleRate: 16000 });
    this.analyser = this.audioCtx.createAnalyser();
    this.analyser.fftSize = 1024;

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const source = this.audioCtx.createMediaStreamSource(stream);
    source.connect(this.analyser);

    // Init ML Model if requested
    if (this.mode === 'ml-swift') {
      this.onnxSession = await ort.InferenceSession.create(modelPath, {
        executionProviders: ['wasm']
      });
    }
  }

  // --- 2. TRACKING LOOP ---

  startTracking(onPitchDetected: (result: PitchResult) => void) {
    if (!this.analyser) throw new Error("Tracker not initialized");

    const timeData = new Float32Array(this.analyser.fftSize);
    const freqData = new Float32Array(this.analyser.frequencyBinCount);

    this.trackingInterval = window.setInterval(async () => {
      if (this.mode === 'ml-swift') {
        this.analyser!.getFloatFrequencyData(freqData);
        const pitch = await this.detectSwiftF0(freqData);
        onPitchDetected({ pitch, probability: pitch > 0 ? 1 : 0 });
      } else {
        this.analyser!.getFloatTimeDomainData(timeData);
        const result = this.mode === 'dsp-yin' 
          ? this.detectYIN(timeData) 
          : this.detectAutocorrelation(timeData);
        onPitchDetected(result);
      }
    }, 16); // ~16ms interval
  }

  stopTracking() {
    if (this.trackingInterval) window.clearInterval(this.trackingInterval);
  }

  // --- 3. ALGORITHMS ---

  private async detectSwiftF0(freqData: Float32Array): Promise<number> {
    if (!this.onnxSession) return -1;

    // SwiftF0 requires specific bins (3 to 134)
    const swiftInput = freqData.slice(3, 134);
    const tensor = new ort.Tensor('float32', swiftInput, [1, 1, 1, 132]);

    const results = await this.onnxSession.run({ input: tensor });
    const logits = results.output.data as Float32Array;

    let maxVal = -Infinity, bestBin = -1;
    for (let b = 0; b < 200; b++) {
      if (logits[b] > maxVal) { maxVal = logits[b]; bestBin = b; }
    }

    return bestBin > 0 ? 46.875 * Math.pow(2, bestBin * (Math.log2(2093.75 / 46.875) / 199)) : -1;
  }

  private detectYIN(buffer: Float32Array): PitchResult {
    // Agent: Inject the standard YIN cumulative mean normalized difference function here.
    // Return format: { pitch: number, probability: number }
    return { pitch: 440, probability: 0.9 }; // Placeholder
  }

  private detectAutocorrelation(buffer: Float32Array): PitchResult {
    // Agent: Inject the standard Autocorrelation/NSDF function here.
    // Return format: { pitch: number, probability: number }
    return { pitch: 440, probability: 0.9 }; // Placeholder
  }
}
